1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const QUOTE_HIGH_ENCH_THRESHOLD = 5;
5	const QUOTE_HIGH_ENCH_RATE = 0.3;
6	const CLAIM_HIGH_ENCH_THRESHOLD = 8;
7	const CLAIM_HIGH_ENCH_RATE = 0.5;
8	const BLOCK_SIZE = 3;
9	const BLOCK_PREMIUM = 60;
10	const LOYALTY_THRESHOLD = 2;
11	const LOYALTY_RATE = 0.2;
12	const FOLLOWUP_RATE = 0.15;
13	const CAP_MULTIPLIER = 2;
14	const DEDUCTIBLE_PER_DAMAGE = 100;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const INSURANCE_VALUES: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const COMPONENT_TYPES = ["rune", "moonstone"];
35	
36	type Item = { type: string; cursed?: boolean; enchantment?: number };
37	
38	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
40	const isCursed = (item: Item): boolean => item.cursed === true;
41	const isHighlyEnchantedForQuote = (item: Item): boolean =>
42	  enchantmentLevel(item) >= QUOTE_HIGH_ENCH_THRESHOLD;
43	const isHighlyEnchantedForClaim = (item: Item): boolean =>
44	  enchantmentLevel(item) >= CLAIM_HIGH_ENCH_THRESHOLD;
45	
46	const sum = (values: number[]): number =>
47	  values.reduce((total, value) => total + value, 0);
48	
49	const sumOfBasePremiums = (items: Item[]): number =>
50	  sum(items.map((item) => BASE_PREMIUMS[item.type]));
51	
52	const groupByType = (items: Item[]): Item[][] => {
53	  const groups: Record<string, Item[]> = {};
54	  for (const item of items) {
55	    if (!groups[item.type]) groups[item.type] = [];
56	    groups[item.type].push(item);
57	  }
58	  return Object.values(groups);
59	};
60	
61	const basePremiumForComponentGroup = (group: Item[]): number =>
62	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumOfBasePremiums(group);
63	
64	const basePremiumFor = (items: Item[]): number => {
65	  const components = items.filter(isComponent);
66	  const nonComponents = items.filter((item) => !isComponent(item));
67	  const componentGroupPremiums = groupByType(components).map(basePremiumForComponentGroup);
68	  return sum(componentGroupPremiums) + sumOfBasePremiums(nonComponents);
69	};
70	
71	const surchargeFor = (
72	  items: Item[],
73	  rate: number,
74	  applies: (item: Item) => boolean,
75	): number =>
76	  sum(items.map((item) => (applies(item) ? BASE_PREMIUMS[item.type] * rate : 0)));
77	
78	const quotePremium = (items: Item[], yearsWithMHPCO: number, quoteIndex: number): number => {
79	  const base = basePremiumFor(items);
80	  const curseSurcharge = surchargeFor(items, CURSE_RATE, isCursed);
81	  const highEnchSurcharge = surchargeFor(items, QUOTE_HIGH_ENCH_RATE, isHighlyEnchantedForQuote);
82	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD ? base * LOYALTY_RATE : 0;
83	  const followupDiscount = quoteIndex > 0 ? base * FOLLOWUP_RATE : 0;
84	  const firstInsuranceFee = base * FIRST_INSURANCE_RATE;
85	  const total = base + curseSurcharge + highEnchSurcharge
86	    - loyaltyDiscount - followupDiscount
87	    + firstInsuranceFee + PROCESSING_FEE;
88	  return Math.ceil(total);
89	};
90	
91	type Policy = { items: Item[]; insuranceSum: number; remainingCap: number };
92	
93	const insuranceSumFor = (items: Item[]): number =>
94	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
95	
96	const reimbursableAmount = (damageAmount: number, item: Item | undefined): number =>
97	  item && isHighlyEnchantedForClaim(item)
98	    ? damageAmount * CLAIM_HIGH_ENCH_RATE
99	    : damageAmount;
100	
101	type Damage = { itemType: string; amount: number };
102	
103	const findItemByType = (items: Item[], type: string): Item | undefined =>
104	  items.find((item) => item.type === type);
105	
106	const validateDamage = (damage: Damage, policy: Policy): void => {
107	  if (damage.amount < 0) {
108	    throw new Error(`negative damage amount: ${damage.amount}`);
109	  }
110	  if (!findItemByType(policy.items, damage.itemType)) {
111	    throw new Error(`${damage.itemType} not in policy`);
112	  }
113	};
114	
115	const countByType = <T>(items: T[], typeOf: (item: T) => string): Record<string, number> => {
116	  const counts: Record<string, number> = {};
117	  for (const item of items) {
118	    const type = typeOf(item);
119	    counts[type] = (counts[type] ?? 0) + 1;
120	  }
121	  return counts;
122	};
123	
124	const validateDamageCounts = (damages: Damage[], policy: Policy): void => {
125	  const damageCounts = countByType(damages, (damage) => damage.itemType);
126	  const policyCounts = countByType(policy.items, (item) => item.type);
127	  for (const type in damageCounts) {
128	    if (damageCounts[type] > (policyCounts[type] ?? 0)) {
129	      throw new Error(`too many ${type} damages: exceed insured count`);
130	    }
131	  }
132	};
133	
134	const validateDamagesAgainstPolicy = (damages: Damage[], policy: Policy): void => {
135	  damages.forEach((damage) => validateDamage(damage, policy));
136	  validateDamageCounts(damages, policy);
137	};
138	
139	const validateItemTypes = (items: Item[]): void => {
140	  for (const item of items) {
141	    if (!(item.type in BASE_PREMIUMS)) {
142	      throw new Error(`unknown item type: ${item.type}`);
143	    }
144	  }
145	};
146	
147	const payoutForDamage = (damage: Damage, policy: Policy): number => {
148	  const item = findItemByType(policy.items, damage.itemType);
149	  const reimbursable = reimbursableAmount(damage.amount, item);
150	  return Math.max(0, Math.floor(reimbursable - DEDUCTIBLE_PER_DAMAGE));
151	};
152	
153	const handleClaim = (step: any, policies: Record<number, Policy>): { payout: number; remainingCap: number } => {
154	  const policy = policies[step.policy];
155	  const damages: Damage[] = step.incident.damages;
156	  validateDamagesAgainstPolicy(damages, policy);
157	  const totalPayout = sum(damages.map((damage) => payoutForDamage(damage, policy)));
158	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
159	  policy.remainingCap -= cappedPayout;
160	  return { payout: cappedPayout, remainingCap: policy.remainingCap };
161	};
162	
163	export const runScenario = (scenario: any): unknown => {
164	  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
165	  let quoteIndex = 0;
166	  const policies: Record<number, Policy> = {};
167	  const results = scenario.steps.map((step: any, stepIndex: number) => {
168	    if (step.op === "claim") {
169	      return handleClaim(step, policies);
170	    }
171	    validateItemTypes(step.items);
172	    const premium = quotePremium(step.items, yearsWithMHPCO, quoteIndex);
173	    const insuranceSum = insuranceSumFor(step.items);
174	    policies[stepIndex] = {
175	      items: step.items,
176	      insuranceSum,
177	      remainingCap: insuranceSum * CAP_MULTIPLIER,
178	    };
179	    quoteIndex++;
180	    return { premium };
181	  });
182	  return { results };
183	};
