3	export const runCli = (input: string): { exitCode: number; stdout: string; stderr: string } => {
4	  try {
5	    const scenario = JSON.parse(input);
6	    const result = runScenario(scenario);
7	    return { exitCode: 0, stdout: JSON.stringify(result), stderr: "" };
8	  } catch (err) {
9	    const message = err instanceof Error ? err.message : String(err);
10	    return { exitCode: 1, stdout: "", stderr: message };
11	  }
12	};
